import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import Footer1 from '../../COMPONENTS/Footer/Footer1';
import Footer2 from '../../COMPONENTS/Footer/Footer2';
import Navbar from '../../COMPONENTS/Navbar/Navbar';
import SingleBanner from '../../COMPONENTS/Banners/SingleBanner';
import UserSidebar from '../../COMPONENTS/UserProfile/UserSidebar';
import AccountSettings from '../../COMPONENTS/UserProfile/AccountSettings';
import ChangePassword from '../../COMPONENTS/UserProfile/ChangePassword';
import UserAddress from '../../COMPONENTS/UserProfile/UserAddress';
import LegalNotice from '../../COMPONENTS/UserProfile/LegalNotice';
import './UserProfile.css';
import loginImage from '../pages/user.jp';


const UserProfile = () => {
    const { activepage } = useParams();
    const [user, setUser] = useState(null);
    const [error, setError] = useState("");
    const [email, setEmail] = useState("");

    useEffect(() => {
        const storedEmail = localStorage.getItem("userEmail");
        if (!storedEmail) {
            setError("🚨 Aucun email trouvé. Veuillez vous reconnecter.");
        } else {
            setEmail(storedEmail);
        }
    }, []);

    useEffect(() => {
        if (!email) return;

        const fetchUserByEmail = async () => {
            try {
                const response = await fetch(`http://localhost:5001/user/email/${email}`);
                if (!response.ok) {
                    throw new Error(`Erreur HTTP : ${response.status}`);
                }
                const data = await response.json();
                if (data.success && data.user) {
                    setUser(data.user);
                } else {
                    throw new Error("Les données utilisateur sont invalides.");
                }
            } catch (err) {
                setError("Erreur lors de la récupération des informations utilisateur.");
                console.error(err);
            }
        };

        fetchUserByEmail();
    }, [email]);

    return (
        <div className='userprofile'>
            <Navbar />
            <SingleBanner 
                heading="My Profile"
                bannerimage="https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&w=774&q=80" 
            />

            {/* 🖼️ Image de profil centrée */}
            <div className="profile-header">
                <div className="profile-image-container">
                    <img 
                        src={user?.imageUrl || "/userq.png"} 
                        alt="Profile" 
                        className="profile-image"
                    />
                </div>
                <h2 className="profile-name">{user?.name || "User Name"}</h2>
            </div>

            <div className='userprofilein'>
                <div className='left'>
                    <UserSidebar activepage={activepage} />
                </div>
                <div className='right'>
                    {activepage === 'accountsettings' && <AccountSettings />}
                    {activepage === 'changepassword' && <ChangePassword />}
                    {activepage === 'address' && <UserAddress />}
                    {activepage === 'legalnotice' && <LegalNotice />}
                    <div className="profile-image-container">
          <img 
            src={user?.imageUrl || "/userq.png"} 
            alt="Profile" 
            className="profile-image" 
          />
        </div>

        <div className='form'>
          <div className='form-group'>
            <label htmlFor='name'>Your Name <span>*</span></label>
            <input 
              type='text' 
              name='name' 
              id='name' 
              value={user?.name || ''} 
              disabled={!user} 
            />
          </div>

          <div className='form-group'>
            <label htmlFor='role'>Role <span>*</span></label>
            <input 
              type='text' 
              name='role' 
              id='role' 
              value={user?.role || ''} 
              disabled={!user}
            />
          </div>

          <div className='form-group'>
            <label htmlFor='email'>Email <span>*</span></label>
            <input 
              type='email' 
              name='email' 
              id='email' 
              value={user?.email || ''} 
              disabled
            />
          </div>
        </div>
                </div>
            </div>

            <Footer1 />
            <Footer2 />
        </div>
    );
};

export default UserProfile;
